package com.company.supervision.application.organization;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;import com.baomidou.mybatisplus.core.metadata.IPage;import com.baomidou.mybatisplus.extension.plugins.pagination.Page;import com.company.supervision.domain.model.organization.*;import com.company.supervision.infrastructure.repository.organization.*;import org.springframework.stereotype.Service;import java.util.*;
@Service public class OrganizationQueryService{private final DepartmentMapper departments;private final PersonMapper persons;private final PersonDepartmentMapper links;public OrganizationQueryService(DepartmentMapper d,PersonMapper p,PersonDepartmentMapper l){departments=d;persons=p;links=l;}
 public List<Map<String,Object>>tree(){List<Map<String,Object>>out=new ArrayList<>();for(Department d:departments.selectList(new LambdaQueryWrapper<Department>().orderByAsc(Department::getOrderNo))){Map<String,Object>m=new LinkedHashMap<>();m.put("id",d.getId());m.put("wecomDepartmentId",d.getWecomDepartmentId());m.put("parentWecomDepartmentId",d.getParentWecomDepartmentId());m.put("name",d.getName());m.put("status",d.getStatus());m.put("syncedAt",d.getSyncedAt());m.put("memberCount",links.countByDepartment(d.getId()));out.add(m);}return out;}
 public IPage<Map<String,Object>>people(Long departmentId,String keyword,Integer status,String gender,String syncStatus,int page,int size){LambdaQueryWrapper<Person>w=new LambdaQueryWrapper<>();if(departmentId!=null)w.inSql(Person::getId,"SELECT person_id FROM supervision_person_department WHERE department_id="+departmentId);if(keyword!=null&&!keyword.isBlank())w.and(x->x.like(Person::getName,keyword).or().like(Person::getWecomUserId,keyword));if(status!=null)w.eq(Person::getStatus,status);if(gender!=null&&!gender.isBlank())w.eq(Person::getGender,gender);if(syncStatus!=null&&!syncStatus.isBlank())w.eq(Person::getSyncStatus,syncStatus);IPage<Person>raw=persons.selectPage(new Page<>(Math.max(1,page),Math.max(1,size)),w.orderByAsc(Person::getName));Page<Map<String,Object>>out=new Page<>(raw.getCurrent(),raw.getSize(),raw.getTotal());out.setRecords(raw.getRecords().stream().map(this::view).toList());return out;}
 public Map<String,Object>person(Long id){Person p=persons.selectById(id);if(p==null)throw new IllegalArgumentException("成员不存在");return view(p);}
 public Map<String,Object>department(Long id){Department d=departments.selectById(id);if(d==null)throw new IllegalArgumentException("部门不存在");Map<String,Object>m=new LinkedHashMap<>();m.put("department",d);m.put("memberCount",links.countByDepartment(id));return m;}
 private Map<String,Object>view(Person p){Map<String,Object>m=new LinkedHashMap<>();m.put("id",p.getId());m.put("wecomUserId",p.getWecomUserId());m.put("name",p.getName());m.put("mobileMasked",p.getMobileMasked());m.put("email",p.getEmail());m.put("positionName",p.getPositionName());m.put("avatarUrl",p.getAvatarUrl());m.put("gender",p.getGender());m.put("status",p.getStatus());m.put("syncStatus",p.getSyncStatus());m.put("syncError",p.getSyncErrorRedacted());m.put("syncedAt",p.getSyncedAt());List<Department>ds=links.departmentsForPerson(p.getId()).stream().map(departments::selectById).filter(Objects::nonNull).toList();m.put("departments",ds);m.put("primaryDepartment",ds.isEmpty()?null:ds.get(0));return m;}}
